"""
codebench_inline — inline rich-output bridge for CodeBench
══════════════════════════════════════════════════════════

Captures matplotlib figures, plotly figures, PIL images, and pandas
DataFrame HTML and ships them to the iPad output panel for inline
display — the same UX as a Jupyter cell, but inside a regular script
run.

Public API
──────────
    codebench_inline.install()
        Hook everything that's available (matplotlib, plotly, PIL).
        Safe to call multiple times — no-ops on already-installed
        backends. Call once at script start (or from sitecustomize).

    codebench_inline.show_png(path: str, caption: str = "")
        Manually ship an existing PNG file to the output panel.

    codebench_inline.show_html(html: str, caption: str = "")
        Manually ship a chunk of HTML.

How it works
────────────
Each captured artifact is written to `$TMPDIR/latex_signals/` as
`inline_<timestamp>_<hash>.json` with shape:

    { "kind": "png" | "html",
      "path": "/abs/path/to/file.png",     # for kind=png
      "html": "<table>...</table>",        # for kind=html
      "caption": "Figure 1" }

The Swift-side `LaTeXEngine` event source (the same vnode watcher used
for LaTeX compile signals) picks them up and renders into the editor's
output panel. We piggyback on the LaTeX engine's existing infrastructure
rather than introduce a new IPC channel — it already runs on iPad's
main runloop and has filesystem-event triggers.

Why not just use matplotlib's "agg" backend + manual savefig?
─────────────────────────────────────────────────────────────
Users write `plt.show()` (and tutorials say to). Tying that call to
our PNG export is the no-friction path. Same for plotly's `fig.show()`,
PIL's `Image.show()`, and the IPython `_repr_html_` protocol that
pandas DataFrames use to render as tables.
"""

import json
import os
import sys
import time
import hashlib
import tempfile
from typing import Optional

# ─── Signal dir + write helpers ────────────────────────────────────

def _signal_dir() -> str:
    """Match LaTeXEngine.signalDir — `$TMPDIR/latex_signals/`."""
    d = os.path.join(tempfile.gettempdir(), "latex_signals")
    os.makedirs(d, exist_ok=True)
    return d


def _inline_image_dir() -> str:
    """Where captured PNGs live until Swift reads them. Cleaned by Swift."""
    d = os.path.join(tempfile.gettempdir(), "codebench_inline_images")
    os.makedirs(d, exist_ok=True)
    return d


def _write_signal(payload: dict) -> None:
    """Drop one signal JSON file. Atomic write via tmp + rename so the
    Swift-side vnode watcher never sees a half-written file."""
    sig_dir = _signal_dir()
    # Include hash so concurrent writes from different threads don't collide.
    h = hashlib.sha1(repr(payload).encode()).hexdigest()[:8]
    name = "inline_{}_{}.json".format(int(time.time() * 1000), h)
    final = os.path.join(sig_dir, name)
    tmp = final + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(payload, f)
    os.replace(tmp, final)


# ─── Public functional API ────────────────────────────────────────

def show_png(path: str, caption: str = "") -> None:
    """Ship an existing PNG to the output panel."""
    _write_signal({"kind": "png", "path": path, "caption": caption})


def show_html(html: str, caption: str = "") -> None:
    """Ship a chunk of HTML to the output panel.

    HTML is sanitised lightly (Swift side runs it inside the same
    WKWebView that the output panel already uses, so XSS isn't a
    concern — but very long strings get truncated to keep the file
    size sane). Useful for DataFrame .to_html() output.
    """
    if len(html) > 1_000_000:
        html = html[:1_000_000] + "\n<!-- truncated to 1 MB -->"
    _write_signal({"kind": "html", "html": html, "caption": caption})


# ─── matplotlib hook ──────────────────────────────────────────────

_mpl_installed = False

def _install_matplotlib() -> bool:
    """Monkey-patch matplotlib's pyplot.show() (and Figure.show()) to
    save the current figure to PNG and ship it through `show_png`.
    Returns True if matplotlib was importable and we installed the hook."""
    global _mpl_installed
    if _mpl_installed:
        return True
    try:
        import matplotlib                     # noqa: WPS433 (intentional lazy import)
        matplotlib.use("Agg", force=True)     # headless — no Cocoa
        import matplotlib.pyplot as plt
    except Exception as e:
        # matplotlib not installed in this environment, or some other
        # import-time failure — nothing to do.
        sys.stderr.write("[codebench_inline] matplotlib not available: %s\n" % e)
        return False

    img_dir = _inline_image_dir()
    orig_show = plt.show

    def _captured_show(*args, **kwargs):
        # Iterate every active figure, save each to PNG, ship each.
        # mirrors the behaviour Jupyter's inline backend has: a cell
        # that creates multiple figures gets multiple inline images.
        figs = []
        try:
            for num in plt.get_fignums():
                fig = plt.figure(num)
                figs.append(fig)
        except Exception:
            return orig_show(*args, **kwargs)
        for fig in figs:
            ts = int(time.time() * 1000)
            path = os.path.join(img_dir, "fig_{}_{}.png".format(num, ts))
            try:
                fig.savefig(path, dpi=120, bbox_inches="tight", facecolor="white")
            except Exception as e:
                sys.stderr.write("[codebench_inline] savefig failed: %s\n" % e)
                continue
            cap = fig._suptitle.get_text() if getattr(fig, "_suptitle", None) else ""
            show_png(path, caption=cap)
        # Close so subsequent plt.figure() doesn't reuse the same axes.
        # This matches Jupyter's behaviour with `%matplotlib inline`.
        try:
            plt.close("all")
        except Exception:
            pass

    plt.show = _captured_show

    # Also patch Figure.show() so `fig.show()` works the same way
    try:
        from matplotlib.figure import Figure
        _orig_fig_show = Figure.show
        def _fig_show(self, *args, **kwargs):
            ts = int(time.time() * 1000)
            path = os.path.join(img_dir, "fig_inst_{}.png".format(ts))
            self.savefig(path, dpi=120, bbox_inches="tight", facecolor="white")
            cap = self._suptitle.get_text() if getattr(self, "_suptitle", None) else ""
            show_png(path, caption=cap)
        Figure.show = _fig_show
    except Exception:
        pass

    _mpl_installed = True
    return True


# ─── plotly hook ───────────────────────────────────────────────────

_plotly_installed = False

def _install_plotly() -> bool:
    """Patch `plotly.io.show()` so `fig.show()` exports HTML+JS we can
    embed. Plotly figures render as interactive HTML, so we ship the
    full standalone HTML rather than a PNG (which would lose interactivity)."""
    global _plotly_installed
    if _plotly_installed:
        return True
    try:
        import plotly.io as pio
    except Exception:
        return False
    orig_show = pio.show

    def _show(fig, *args, **kwargs):
        try:
            html = pio.to_html(fig, include_plotlyjs="cdn", full_html=True)
            show_html(html, caption="Plotly figure")
        except Exception as e:
            sys.stderr.write("[codebench_inline] plotly export failed: %s\n" % e)
            return orig_show(fig, *args, **kwargs)

    pio.show = _show
    _plotly_installed = True
    return True


# ─── PIL hook ──────────────────────────────────────────────────────

_pil_installed = False

def _install_pil() -> bool:
    """Patch PIL.Image.show() to save the image and ship it inline."""
    global _pil_installed
    if _pil_installed:
        return True
    try:
        from PIL import Image
    except Exception:
        return False

    img_dir = _inline_image_dir()
    orig_show = Image.Image.show

    def _show(self, title: Optional[str] = None, command: Optional[str] = None):
        ts = int(time.time() * 1000)
        path = os.path.join(img_dir, "pil_{}.png".format(ts))
        try:
            (self.convert("RGB") if self.mode == "CMYK" else self).save(path, "PNG")
        except Exception as e:
            sys.stderr.write("[codebench_inline] PIL save failed: %s\n" % e)
            return orig_show(self, title=title, command=command)
        show_png(path, caption=title or "")

    Image.Image.show = _show
    _pil_installed = True
    return True


# ─── pandas hook ───────────────────────────────────────────────────

_pandas_installed = False

def _install_pandas() -> bool:
    """Set the default display.notebook_repr_html so DataFrames render
    as HTML tables in our output panel when the user does
    `display(df)` or `from IPython.display import display; display(df)`."""
    global _pandas_installed
    if _pandas_installed:
        return True
    try:
        import pandas as pd
    except Exception:
        return False
    try:
        # Make sure HTML repr is enabled — pandas does this by default
        # in notebook context but we're not in one, so force it.
        pd.set_option("display.notebook_repr_html", True)
    except Exception:
        pass

    # We don't override DataFrame.__repr__ globally — users still want
    # plain-text in print(). Instead expose a helper they call:
    #     from codebench_inline import display
    # which detects DataFrame / Series and ships HTML.
    _pandas_installed = True
    return True


# ─── IPython-style `display` ──────────────────────────────────────

def display(obj, caption: str = "") -> None:
    """Smart-display: figures out the right format for `obj` and ships
    it inline. Works for pandas DataFrame/Series, matplotlib Figure,
    PIL Image, plotly Figure, plain strings (rendered as monospace
    HTML), and anything with a _repr_html_."""
    # Pandas
    try:
        import pandas as pd
        if isinstance(obj, (pd.DataFrame, pd.Series)):
            html = '<div style="font-family:-apple-system,SF Pro,sans-serif">'
            html += obj.to_html(max_rows=200, max_cols=50)
            html += '</div>'
            show_html(html, caption=caption)
            return
    except Exception:
        pass
    # Matplotlib Figure
    try:
        from matplotlib.figure import Figure
        if isinstance(obj, Figure):
            obj.show()  # the patched one above
            return
    except Exception:
        pass
    # PIL Image
    try:
        from PIL import Image
        if isinstance(obj, Image.Image):
            obj.show()  # the patched one above
            return
    except Exception:
        pass
    # _repr_html_ protocol (catch-all for HTML-rich objects)
    if hasattr(obj, "_repr_html_"):
        try:
            html = obj._repr_html_()
            if html:
                show_html(html, caption=caption); return
        except Exception:
            pass
    # Fallback: stringified repr in a <pre>
    show_html("<pre>" + repr(obj) + "</pre>", caption=caption)


# ─── One-shot installer ───────────────────────────────────────────

def install() -> dict:
    """Install all available hooks. Returns a dict {name: installed}."""
    result = {
        "matplotlib": _install_matplotlib(),
        "plotly":     _install_plotly(),
        "pil":        _install_pil(),
        "pandas":     _install_pandas(),
    }
    # Background watcher for `.npy/.npz` quick-look requests from the
    # Swift-side DataQuickLookViewController. Starts a daemon thread
    # once; subsequent calls are no-ops.
    try:
        _serve_numpy_quicklook()
        result["numpy_quicklook"] = True
    except Exception:
        result["numpy_quicklook"] = False
    # Background watcher for notebook cell-execution requests from
    # the Swift-side NotebookViewController. Daemon thread per session.
    try:
        _serve_notebook()
        result["notebook"] = True
    except Exception:
        result["notebook"] = False
    # Auto-render .ipynb files when they're opened in the editor —
    # bridges the gap until the Swift NotebookViewController ships.
    # Watches `$TMPDIR/latex_signals/current_editor_file.txt` (which
    # CodeEditorViewController.publishCurrentEditorFile writes on
    # every file open) and triggers preview rendering for .ipynb.
    try:
        _serve_ipynb_autorender()
        result["ipynb_autorender"] = True
    except Exception:
        result["ipynb_autorender"] = False
    return result


# Convenience: if the module is imported under the magic name
# `codebench_inline.auto`, install immediately.
# Use:   import codebench_inline.auto    or    -m codebench_inline.auto
auto = sys.modules[__name__]


# ─── Notebook executor ────────────────────────────────────────────
#
# Handles `notebook_exec_request_*.json` from the Swift-side
# NotebookViewController. Maintains one namespace per `scope` string
# so concurrent notebooks don't share state.

_NB_NAMESPACES: dict = {}     # {scope: {globals_dict}}

def _nb_get_namespace(scope: str) -> dict:
    """Lazy-init a namespace for the given notebook scope."""
    if scope not in _NB_NAMESPACES:
        ns = {"__name__": "__main__", "__nb_scope__": scope}
        # Seed with the convenience imports a fresh script would get.
        try:
            import numpy as np
            ns["np"] = np
        except ImportError: pass
        try:
            import pandas as pd
            ns["pd"] = pd
        except ImportError: pass
        try:
            import matplotlib.pyplot as plt
            ns["plt"] = plt
        except ImportError: pass
        # Install our inline backend so plt.show() captures inline
        try:
            install()
        except Exception: pass
        _NB_NAMESPACES[scope] = ns
    return _NB_NAMESPACES[scope]


def _serve_notebook() -> None:
    """Watch for notebook execution requests; idempotent."""
    import threading
    if getattr(_serve_notebook, "_started", False):
        return
    _serve_notebook._started = True

    def _loop():
        sig_dir = _signal_dir()
        while True:
            try:
                # Restart-kernel signals first
                for name in os.listdir(sig_dir):
                    if name.startswith("notebook_restart_") and name.endswith(".txt"):
                        scope = name[len("notebook_restart_"):-len(".txt")]
                        _NB_NAMESPACES.pop(scope, None)
                        try: os.remove(os.path.join(sig_dir, name))
                        except OSError: pass
                # Exec requests
                for name in sorted(os.listdir(sig_dir)):
                    if not (name.startswith("notebook_exec_request_") and name.endswith(".json")):
                        continue
                    req_path = os.path.join(sig_dir, name)
                    try:
                        with open(req_path, "r", encoding="utf-8") as f:
                            req = json.load(f)
                        os.remove(req_path)
                    except (OSError, ValueError):
                        continue
                    _nb_execute(sig_dir, req)
            except Exception:
                pass
            time.sleep(0.15)

    t = threading.Thread(target=_loop, daemon=True, name="codebench-notebook")
    t.start()


def _nb_execute(sig_dir: str, req: dict) -> None:
    """Run `req['code']` in scope `req['scope']`, capture stdout/stderr/
    result/plots, write to notebook_exec_response_<exec_id>.json."""
    import io as _io
    import contextlib
    import base64
    import traceback as _tb
    exec_id = req.get("exec_id", "")
    scope   = req.get("scope", "default")
    code    = req.get("code", "")
    if not exec_id or not code:
        return
    ns = _nb_get_namespace(scope)
    stdout_buf = _io.StringIO()
    stderr_buf = _io.StringIO()
    result_str = ""
    error_obj = None
    image_b64 = ""
    html_str = ""

    # Capture matplotlib figures by checking get_fignums() after exec
    fig_nums_before = []
    try:
        import matplotlib.pyplot as plt
        fig_nums_before = list(plt.get_fignums())
    except Exception:
        plt = None

    # Determine whether the last line is an expression (for repl-style result)
    try:
        import ast
        tree = ast.parse(code, mode="exec")
        last_is_expr = (len(tree.body) > 0 and isinstance(tree.body[-1], ast.Expr))
    except SyntaxError:
        last_is_expr = False
        tree = None

    try:
        with contextlib.redirect_stdout(stdout_buf), \
             contextlib.redirect_stderr(stderr_buf):
            if last_is_expr and tree is not None:
                # Run all but last as exec, last as eval
                if len(tree.body) > 1:
                    body_mod = ast.Module(body=tree.body[:-1], type_ignores=[])
                    exec(compile(body_mod, "<cell>", "exec"), ns)
                expr_node = ast.Expression(body=tree.body[-1].value)
                val = eval(compile(expr_node, "<cell>", "eval"), ns)
                if val is not None:
                    result_str = repr(val)
            else:
                exec(compile(code, "<cell>", "exec"), ns)
    except Exception:
        et, ev, tb = sys.exc_info()
        formatted = _tb.format_exception(et, ev, tb)
        error_obj = {
            "ename":     getattr(et, "__name__", str(et)),
            "evalue":    str(ev),
            "traceback": formatted,
        }

    # Capture any new figures
    if plt is not None:
        try:
            for num in plt.get_fignums():
                if num in fig_nums_before:
                    continue
                fig = plt.figure(num)
                buf = _io.BytesIO()
                fig.savefig(buf, format="png", dpi=110, bbox_inches="tight", facecolor="white")
                image_b64 = base64.b64encode(buf.getvalue()).decode("ascii")
                break  # one image per cell for simplicity
            plt.close("all")
        except Exception:
            pass

    resp = {
        "exec_id": exec_id,
        "stdout":  stdout_buf.getvalue(),
        "stderr":  stderr_buf.getvalue(),
        "result":  result_str,
        "image_b64": image_b64,
        "html":    html_str,
    }
    if error_obj:
        resp["error"] = error_obj

    resp_path = os.path.join(sig_dir, "notebook_exec_response_%s.json" % exec_id)
    tmp = resp_path + ".tmp"
    try:
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(resp, f)
        os.replace(tmp, resp_path)
    except OSError:
        pass


# ─── .ipynb auto-render bridge ────────────────────────────────────
#
# Watches `current_editor_file.txt` (written by Swift's
# CodeEditorViewController.publishCurrentEditorFile on every file
# open) — when the path ends in `.ipynb`, render to HTML and trigger
# preview pane load. Lets users see notebooks rendered without the
# Swift NotebookViewController being compiled in.

def _serve_ipynb_autorender() -> None:
    """Watch the current-editor-file signal and auto-render .ipynb."""
    import threading
    if getattr(_serve_ipynb_autorender, "_started", False):
        return
    _serve_ipynb_autorender._started = True

    def _loop():
        sig_dir = _signal_dir()
        watch = os.path.join(sig_dir, "current_editor_file.txt")
        last_path = ""
        last_mtime = 0.0
        while True:
            try:
                if os.path.exists(watch):
                    mt = os.path.getmtime(watch)
                    if mt != last_mtime:
                        last_mtime = mt
                        with open(watch, "r", encoding="utf-8") as f:
                            current = f.read().strip()
                        if current and current != last_path:
                            last_path = current
                            if current.lower().endswith(".ipynb"):
                                _autorender_ipynb(current)
            except Exception:
                pass
            time.sleep(0.4)

    t = threading.Thread(target=_loop, daemon=True, name="codebench-ipynb-watch")
    t.start()


def _autorender_ipynb(nb_path: str) -> None:
    """Render the given .ipynb to HTML and ask the preview pane to load it."""
    if not os.path.isfile(nb_path):
        return
    try:
        with open(nb_path, "r", encoding="utf-8") as f:
            nb = json.load(f)
    except Exception:
        return
    try:
        html, count = _render_ipynb_html(nb, nb_path)
    except Exception as e:
        sys.stderr.write("[codebench_inline] ipynb render failed: %s\n" % e)
        return
    out_dir = os.path.expanduser("~/Documents/ToolOutputs")
    try:
        os.makedirs(out_dir, exist_ok=True)
    except OSError:
        out_dir = tempfile.gettempdir()
    stem = os.path.splitext(os.path.basename(nb_path))[0]
    out_path = os.path.join(out_dir, stem + ".nb.html")
    try:
        with open(out_path, "w", encoding="utf-8") as f:
            f.write(html)
    except OSError:
        return
    # Trigger preview pane load via existing preview_request.txt protocol
    sig = _signal_dir()
    try:
        with open(os.path.join(sig, "preview_request.txt"), "w",
                  encoding="utf-8") as f:
            f.write(out_path)
    except OSError:
        pass


def _render_ipynb_html(nb: dict, nb_path: str):
    """Render a parsed notebook to a self-contained HTML page.
    Returns (html_str, cell_count)."""
    import base64 as _b64  # noqa
    cells = nb.get("cells", [])
    parts = []
    for idx, cell in enumerate(cells):
        ctype = cell.get("cell_type", "unknown")
        src = cell.get("source", "")
        if isinstance(src, list):
            src = "".join(src)
        if ctype == "code":
            ec = cell.get("execution_count")
            ec_str = "[%s]" % ec if ec else "[ ]"
            parts.append("<div class='cell code-cell'>")
            parts.append(
                "<div class='cell-head'>"
                "<span class='ec'>%s</span>"
                "<span class='kind'>code · cell %d</span></div>"
                % (ec_str, idx + 1))
            parts.append("<pre class='src'><code>%s</code></pre>"
                         % _ipynb_html_escape(src))
            for out in cell.get("outputs", []) or []:
                otype = out.get("output_type", "")
                if otype == "stream":
                    text = out.get("text", "")
                    if isinstance(text, list):
                        text = "".join(text)
                    cls = "out-err" if out.get("name") == "stderr" else "out-stream"
                    parts.append("<pre class='%s'>%s</pre>"
                                 % (cls, _ipynb_html_escape(text)))
                elif otype in ("execute_result", "display_data"):
                    data = out.get("data", {}) or {}
                    if "image/png" in data:
                        b64 = data["image/png"]
                        if isinstance(b64, list):
                            b64 = "".join(b64)
                        parts.append(
                            "<img class='out-img' "
                            "src='data:image/png;base64,%s'>" % b64.strip())
                    elif "text/html" in data:
                        h = data["text/html"]
                        if isinstance(h, list):
                            h = "".join(h)
                        parts.append("<div class='out-html'>%s</div>" % h)
                    elif "text/plain" in data:
                        t = data["text/plain"]
                        if isinstance(t, list):
                            t = "".join(t)
                        parts.append("<pre class='out-result'>%s</pre>"
                                     % _ipynb_html_escape(t))
                elif otype == "error":
                    ename = out.get("ename", "Error")
                    evalue = out.get("evalue", "")
                    tb = out.get("traceback", []) or []
                    tb_text = "\n".join(tb) if isinstance(tb, list) else str(tb)
                    import re as _re
                    tb_text = _re.sub(r'\x1b\[[0-9;]*[A-Za-z]', '', tb_text)
                    parts.append(
                        "<pre class='out-err'><strong>%s: %s</strong>\n%s</pre>"
                        % (_ipynb_html_escape(ename),
                           _ipynb_html_escape(evalue),
                           _ipynb_html_escape(tb_text)))
            parts.append("</div>")
        elif ctype == "markdown":
            try:
                from markdown_it import MarkdownIt
                opts = {"breaks": True, "html": True, "typographer": True}
                try:
                    import linkify_it  # noqa
                    opts["linkify"] = True
                except ImportError:
                    pass
                rendered = (MarkdownIt("gfm-like", opts)
                            .enable(["table", "strikethrough"]).render(src))
            except Exception:
                rendered = "<pre>" + _ipynb_html_escape(src) + "</pre>"
            parts.append(
                "<div class='cell md-cell'>"
                "<div class='cell-head'>"
                "<span class='kind'>markdown · cell %d</span></div>"
                "<div class='md-body'>%s</div></div>" % (idx + 1, rendered))
        else:
            parts.append(
                "<div class='cell unknown-cell'>"
                "<div class='cell-head'>"
                "<span class='kind'>%s · cell %d</span></div>"
                "<pre>%s</pre></div>"
                % (_ipynb_html_escape(ctype), idx + 1,
                   _ipynb_html_escape(src)))

    full = _IPYNB_TEMPLATE % {
        "title":    _ipynb_html_escape(os.path.basename(nb_path)),
        "filename": _ipynb_html_escape(nb_path),
        "count":    len(cells),
        "body":     "".join(parts),
    }
    return full, len(cells)


def _ipynb_html_escape(s):
    if not isinstance(s, str):
        s = str(s)
    return (s.replace("&", "&amp;")
             .replace("<", "&lt;")
             .replace(">", "&gt;"))


