# ─── NumPy quick-look helper ──────────────────────────────────────
#
# Called by the Swift-side DataQuickLookViewController when the user
# long-presses a `.npy` or `.npz` file. We load the array, format it as
# an HTML table, and write to the response file the Swift side polls.
#
# Path is captured by a small watcher thread spun up on first call.

def _serve_numpy_quicklook() -> None:
    """Start the background watcher that handles numpy quick-look
    requests. Idempotent — safe to call multiple times."""
    import threading
    if getattr(_serve_numpy_quicklook, "_started", False):
        return
    _serve_numpy_quicklook._started = True

    def _loop():
        sig_dir = _signal_dir()
        req_path = os.path.join(sig_dir, "numpy_quicklook_request.txt")
        resp_path = os.path.join(sig_dir, "numpy_quicklook_response.html")
        while True:
            try:
                if os.path.exists(req_path):
                    with open(req_path, "r", encoding="utf-8") as f:
                        path = f.read().strip()
                    try:
                        os.remove(req_path)
                    except Exception:
                        pass
                    html = _render_numpy_file(path)
                    tmp = resp_path + ".tmp"
                    with open(tmp, "w", encoding="utf-8") as f:
                        f.write(html)
                    os.replace(tmp, resp_path)
            except Exception:
                pass
            time.sleep(0.2)

    t = threading.Thread(target=_loop, daemon=True, name="codebench-numpy-ql")
    t.start()


def _render_numpy_file(path: str) -> str:
    """Load `.npy` or `.npz` and render to a stand-alone HTML table."""
    try:
        import numpy as np
    except Exception:
        return _html_error("numpy not installed.")
    try:
        if path.endswith(".npz"):
            data = np.load(path, allow_pickle=False)
            arrays = {k: data[k] for k in data.files}
        else:
            arr = np.load(path, allow_pickle=False)
            arrays = {"array": arr}
    except Exception as e:
        return _html_error("Could not load: %s" % e)

    parts = ["""<!doctype html><html><head><meta charset='utf-8'>
<meta name='viewport' content='width=device-width,initial-scale=1'>
<style>
    body { margin:0; padding:14px; background:#0a0a0f; color:#f0f0f5;
           font:13px/1.5 -apple-system, SF Pro, sans-serif; }
    h3 { color:#a855f7; margin:18px 0 6px; }
    .meta { color:#a8a8b8; font-size:11px; margin-bottom:8px; }
    table { border-collapse:collapse; font-family:'SF Mono', Menlo, monospace; font-size:11px; }
    th, td { border:1px solid #2a2a42; padding:4px 8px; text-align:right; }
    th { background:#1a1a28; color:#a855f7; }
    tr:nth-child(even) td { background:#12121a; }
</style></head><body>"""]
    for name, arr in arrays.items():
        parts.append("<h3>%s</h3>" % name)
        parts.append("<div class='meta'>shape=%s · dtype=%s · %d bytes</div>" %
                     (arr.shape, arr.dtype, arr.nbytes))
        if arr.ndim == 0:
            parts.append("<pre>%s</pre>" % arr)
        elif arr.ndim == 1:
            parts.append("<table><thead><tr><th>i</th><th>value</th></tr></thead><tbody>")
            for i, v in enumerate(arr[:1000]):
                parts.append("<tr><td>%d</td><td>%s</td></tr>" % (i, v))
            if arr.size > 1000:
                parts.append("<tr><td colspan=2>… %d more rows</td></tr>" % (arr.size - 1000))
            parts.append("</tbody></table>")
        elif arr.ndim == 2:
            rows, cols = arr.shape
            r_cap = min(rows, 500)
            c_cap = min(cols, 50)
            parts.append("<table><thead><tr><th>row \\ col</th>")
            for c in range(c_cap):
                parts.append("<th>%d</th>" % c)
            parts.append("</tr></thead><tbody>")
            for i in range(r_cap):
                parts.append("<tr><th>%d</th>" % i)
                for c in range(c_cap):
                    parts.append("<td>%s</td>" % arr[i, c])
                parts.append("</tr>")
            if rows > r_cap:
                parts.append("<tr><td colspan=%d>… %d more rows</td></tr>" % (c_cap+1, rows - r_cap))
            parts.append("</tbody></table>")
        else:
            # 3+D: show shape + flatten preview
            parts.append("<pre>%s</pre>" % np.array2string(arr, threshold=200))
    parts.append("</body></html>")
    return "".join(parts)


def _html_error(msg: str) -> str:
    return ("<html><body style='font:13px sans-serif;color:#fbbf24;"
            "background:#0a0a0f;padding:20px'>⚠️ " + msg + "</body></html>")

